      // prompt: skip if localStorage has ri_visited
    }
    if (visited) {
      setTimeout(() => setLoading(false), 0);
    } else {
      const timer = setTimeout(() => {
        setLoading(false);
        localStorage.setItem('ri_visited', 'true');
      }, 2000);
      return () => clearTimeout(timer);
