            <div className="text-2xl">📚</div>
            <div className="text-xs leading-tight font-medium text-[var(--color-ink)]">
              BS Grewal sold ₹475<br /><span className="text-[var(--color-dust)]">Kukatpally · 2 min ago</span>
            </div>
