      {/* LIVE TICKER */}
      <div className="bg-[var(--color-rust)] text-white py-2 overflow-hidden ticker-wrap relative">
        <div className="flex whitespace-nowrap animate-ticker ticker-inner text-sm font-bold tracking-wider">
