                                    {book.title}
                                </Link>
                                <p className="text-[10px] text-[var(--color-dust)] uppercase mb-3 flex-1">{book.author}</p>

                                <div className="mb-4">
                                    <div className="flex items-baseline gap-2">
                                        <span className="font-mono text-lg font-bold text-[var(--color-sage)]">₹{book.ourPrice}</span>
                                        <span className="font-mono text-xs line-through text-[var(--color-dust)]">₹{book.mrp}</span>
                                    </div>
                                </div>

                                <div className="flex gap-2 mt-auto">
                                    <button
                                        onClick={(e) => { e.preventDefault(); addCart(book); toast.success(`Added to cart: ${book.title}`); }}
                                        className="flex-1 bg-[var(--color-ink)] hover:bg-[var(--color-rust)] text-white py-2 text-xs font-bold rounded-sm transition-colors flex items-center justify-center gap-1"
                                    >
                                        <ShoppingCart size={14} /> Add to Cart
                                    </button>
                                    <a
                                        href={waBook(book)}
                                        target="_blank" rel="noopener noreferrer"
                                        className="w-8 flex items-center justify-center bg-[#25D366]/10 text-[#25D366] rounded-sm hover:bg-[#25D366] hover:text-white transition-colors"
                                    >
                                        <MessageCircle size={16} />
                                    </a>
                                </div>
                            </div>
                        </div>
                    ))}
                </div>

            </div>
        </div>
    );
}

"use client";

import React, { useState } from 'react';
import { clsx } from 'clsx';
import { Book } from '@/lib/data/books';

interface BookCoverImageProps {
    book: Book | { title: string; isbn: string; category: string };
    className?: string;
    style?: React.CSSProperties;
}

const CATEGORY_GRADIENTS: Record<string, string> = {
    engineering: 'linear-gradient(135deg, #1a3a6e, #2d6abf)',
    medical: 'linear-gradient(135deg, #0d5c3c, #1a8f5e)',
    jee: 'linear-gradient(135deg, #6b1a1a, #c0392b)',
    upsc: 'linear-gradient(135deg, #2c1a6e, #6c3fb5)',
    selfhelp: 'linear-gradient(135deg, #C94A2D, #E8A020)',
    fiction: 'linear-gradient(135deg, #1A1208, #8B7355)',
    school: 'linear-gradient(135deg, #4A7C59, #2d5c3e)',
    default: 'linear-gradient(135deg, #8B7355, #C94A2D)',
};

const VERIFIED_GOOGLE_IDS: Record<string, string> = {
    '9788174091956': 'SY9OAQAAIAAJ',
    '9780262033848': 'BgpZzgEACAAJ',
    '9781119800361': 'P9WBEAAAQBAJ',
    '9788126554232': 'LF4_AQAAQBAJ',
    '9780133918922': 'COKRAQAAQBAJ',
    '9780078022159': 'qbAlMQEACAAJ',
    '9780132126953': 'o3l_QgAACAAJ',
    '9780199476299': 'y9MZAQAAIAAJ',
    '9788177091878': 'f9ZOAQAAIAAJ',
    '9788177092080': 'xpSDAQAAIAAJ',
    '9789313191797': 'GqpbzgEACAAJ',
    '9780702052309': 'UbyzswEACAAJ',
    '9788123924854': 'bdRkzgEACAAJ',
    '9780323597128': 'MWKItAEACAAJ',
    '9780323353175': 'qgBOjgEACAAJ',
    '9781259644030': 'oYFGzgEACAAJ',
    '9789352704996': 'a7J6zQEACAAJ',
    '9781138295773': '3xVKDgAAQBAJ',
    '9789353168933': 'AHkYzQEACAAJ',
    '9780143031345': 'MvKlAAAACAAJ',
    '9780195668452': 'ZSBGAQAAIAAJ',
    '9789352535057': 'dJ5lzQEACAAJ',
    '9781847941831': 'XfFvDwAAQBAJ',
    '8173711461': 'E4p2CwAAQBAJ',
    '9780062315007': 'FP_PAgAAQBAJ',
    '9780804139021': 'ZoOKCgAAQBAJ',
    '9788190804547': 'LB5bngEACAAJ',
};

export default function BookCoverImage({ book, className, style }: BookCoverImageProps) {
    const [tier, setTier] = useState<1 | 2 | 3 | 4>(1);
    const [loading, setLoading] = useState(true);

    // Determine current image URL based on tier
    let src = '';
    if (tier === 1) {
        const googleId = VERIFIED_GOOGLE_IDS[book.isbn];
        if (googleId) {
            src = `https://books.google.com/books/content?id=${googleId}&printsec=frontcover&img=1&zoom=1&source=gbs_api`;
        } else {
            // Fallback immediately if no verified ID
            src = `https://covers.openlibrary.org/b/isbn/${book.isbn}-L.jpg`;
        }
    } else if (tier === 2) {
        src = `https://covers.openlibrary.org/b/isbn/${book.isbn}-L.jpg`;
    } else if (tier === 3) {
        src = `https://covers.openlibrary.org/b/isbn/${book.isbn}-M.jpg`;
    }

    const handleError = () => {
        if (tier < 4) {
            setTier((t) => (t + 1) as any);
        }
    };

    const gradient = CATEGORY_GRADIENTS[book.category] || CATEGORY_GRADIENTS.default;

    return (
        <div
            className={clsx('relative overflow-hidden bg-[var(--color-paper)] shadow-md rounded-sm', className)}
            style={{ aspectRatio: '0.72', ...style }}
        >
            {/* Loading Skeleton */}
            {loading && tier < 4 && (
                <div className="absolute inset-0 bg-black/5 animate-pulse" />
            )}

            {/* Tier 4 Fallback (CSS Gradient) */}
            {(tier === 4 || (tier === 1 && !src)) && (
                <div
                    className="absolute inset-0 flex flex-col items-center justify-center p-4 text-center text-white"
                    style={{ background: gradient }}
                >
                    <div className="text-4xl mb-2 shadow-sm">📚</div>
                    <div className="font-display font-bold text-sm leading-tight line-clamp-4 drop-shadow-md">
                        {book.title}
                    </div>
                </div>
            )}

            {/* Image layers for Tier 1-3 */}
            {tier < 4 && src && (
                // eslint-disable-next-line @next/next/no-img-element
                <img
                    src={src}
                    alt={book.title}
                    className={clsx(
                        'absolute inset-0 w-full h-full object-cover origin-center transition-opacity duration-300',
                        loading ? 'opacity-0' : 'opacity-100'
                    )}
                    onLoad={() => setLoading(false)}
                    onError={handleError}
                    crossOrigin="anonymous"
                />
            )}
        </div>
    );
}

import React from 'react';
import { clsx } from 'clsx';
import { twMerge } from 'tailwind-merge';

type LogoVariant = 'nav' | 'hero' | 'footer' | 'loader' | 'icon';

interface LogoProps {
    variant: LogoVariant;
    darkBg?: boolean;
    onClick?: () => void;
    className?: string;
}

export default function RebookIndiaLogo({ variant, darkBg = false, onClick, className }: LogoProps) {
    const isNav = variant === 'nav';
    const isHero = variant === 'hero';
    const isFooter = variant === 'footer';
    const isLoader = variant === 'loader';
    const isIcon = variant === 'icon';

    const sphereSize = isLoader ? 72 : isIcon ? 64 : isHero ? 58 : isFooter ? 44 : 40;
    const textSize = isLoader ? 36 : isHero ? 30 : isFooter ? 24 : 22;
    const showTagline = isHero || isFooter || isLoader;
    const gap = isLoader ? 16 : isHero ? 14 : isFooter ? 12 : 10;

    const bookH = sphereSize * 0.34;
    const pageW = sphereSize * 0.22;
    const spineW = sphereSize * 0.04;

    const sparkSize = sphereSize * 0.13;
    const badgeSize = sphereSize * 0.24;

    return (
        <div
            className={twMerge(
                'relative flex items-center select-none',
                onClick && 'cursor-pointer hover:opacity-95 transition-opacity',
                className
            )}
            onClick={onClick}
            style={{ gap: `${gap}px` }}
        >
            {/* SPHERE */}
            <div
                className="relative rounded-full flex-shrink-0"
                style={{
                    width: sphereSize,
                    height: sphereSize,
                    background: 'radial-gradient(circle at 38% 32%, #F5C842 0%, #E8A020 42%, #C94A2D 100%)',
                    boxShadow: '0 4px 16px rgba(201,74,45,0.4), 0 0 0 1.5px rgba(232,160,32,0.25)',
                }}
            >
                {/* Sphere Container for clipping */}
                <div className="absolute inset-0 rounded-full overflow-hidden">
                    {/* GLOBE LINES */}
                    <div
                        className="absolute rounded-full border border-[rgba(26,18,8,0.18)]"
                        style={{ width: '100%', height: '28%', top: '36%', borderWidth: '1.5px' }}
                    />
                    <div className="absolute w-full h-[1px] bg-[rgba(26,18,8,0.13)] top-1/2" />
                    <div className="absolute h-full w-[1px] bg-[rgba(26,18,8,0.13)] left-1/2" />

                    {/* OPEN BOOK */}
                    <div className="absolute inset-0 flex items-center justify-center z-10" style={{ perspective: '100px' }}>
                        {/* Left Page */}
                        <div
                            style={{
                                width: pageW,
                                height: bookH,
                                background: 'rgba(250,246,236,0.93)',
                                borderRadius: '2px 0 0 2px',
                                display: 'flex',
                                flexDirection: 'column',
                                justifyContent: 'space-evenly',
                                padding: '1px',
                                transform: 'rotateY(10deg)'
                            }}
                        >
                            {[1, 2, 3, 4].map(i => (
                                <div key={i} className="bg-[#8B7355]/50 h-[1.5px] rounded-full" style={{ width: i === 4 ? '60%' : '90%', marginLeft: 'auto' }} />
                            ))}
                        </div>
                        {/* Spine */}
                        <div
                            style={{
                                width: spineW,
                                height: bookH,
                                background: '#C94A2D',
                                opacity: 0.9,
                                borderRadius: '1px'
                            }}
                        />
                        {/* Right Page */}
                        <div
                            style={{
                                width: pageW,
                                height: bookH,
                                background: 'rgba(250,246,236,0.82)',
                                borderRadius: '0 2px 2px 0',
                                display: 'flex',
                                flexDirection: 'column',
                                justifyContent: 'space-evenly',
                                padding: '1px',
                                transform: 'rotateY(-10deg)'
                            }}
                        >
                            {[1, 2, 3, 4].map(i => (
                                <div key={i} className="bg-[#8B7355]/50 h-[1.5px] rounded-full" style={{ width: i === 4 ? '65%' : '90%' }} />
                            ))}
                        </div>
                    </div>
                </div>

                {/* GOLD SPARK */}
                <div
                    className="absolute z-20 rounded-full"
                    style={{
                        width: sparkSize,
                        height: sparkSize,
                        top: sphereSize * 0.10,
                        right: sphereSize * 0.10,
                        background: 'radial-gradient(circle at 35% 35%, #fff 20%, #F5C842 100%)',
                        boxShadow: '0 0 8px rgba(245,200,66,0.9)'
                    }}
                />

                {/* RUPEE BADGE */}
                <div
                    className="absolute z-20 flex items-center justify-center bg-[#C94A2D] text-[#FAF6EC] font-display font-bold rounded-full border border-white/20 shadow-sm"
                    style={{
                        width: badgeSize,
                        height: badgeSize,
                        bottom: sphereSize * 0.10,
                        left: sphereSize * -0.05,
                        fontSize: badgeSize * 0.65,
                        lineHeight: 1
                    }}
                >
                    ₹
                </div>
            </div>

            {/* TEXT PART */}
            {!isIcon && (
                <div className="flex flex-col justify-center">
                    <div className="tracking-tight leading-none" style={{ fontSize: textSize }}>
                        <span className={clsx("font-display font-bold", darkBg ? "text-[var(--color-cream)]" : "text-[var(--color-ink)]")}>
                            Rebook{" "}
                        </span>
                        <span className="font-display font-normal text-[var(--color-rust)]">
                            India
                        </span>
                    </div>

                    {showTagline && (
                        <div className="mt-1 flex flex-col w-full">
